INSERT INTO `services` VALUES
(1,'Hipnoterapi Anak','hipnoterapi-anak','Terapi khusus untuk anak-anak yang mengalami susah makan, kurang fokus, trauma, atau masalah perilaku lainnya. Pendekatan lembut dan menyenangkan.','fa-child','Anak',350000.00,'90-120 menit',1,1,'2025-12-25 08:46:27'),
(2,'Hipnoterapi Remaja','hipnoterapi-remaja','Membantu remaja mengatasi kecemasan, kurang percaya diri, bullying, prokrastinasi, dan masalah akademik dengan pendekatan modern dan Islami.','fa-user-graduate','Remaja',350000.00,'90-120 menit',1,2,'2025-12-25 08:46:27'),
(3,'Manajemen Stres & Kecemasan','manajemen-stres-kecemasan','Terapi untuk mengatasi stres berlebihan, kecemasan, panic attack, dan gangguan psikosomatis dengan teknik relaksasi mendalam.','fa-brain','Dewasa',350000.00,'90-120 menit',1,3,'2025-12-25 08:46:27'),
(4,'Trauma & Luka Batin','trauma-luka-batin','Membantu menyembuhkan trauma masa lalu, luka batin, PTSD, dan pengalaman menyakitkan dengan metode hipnoterapi yang aman dan efektif.','fa-heart-crack','Dewasa',350000.00,'90-120 menit',1,4,'2025-12-25 08:46:27'),
(5,'Konseling Pasangan & Keluarga','konseling-pasangan-keluarga','Terapi untuk mengatasi konflik rumah tangga, masalah komunikasi, dan memperbaiki hubungan dengan pasangan atau keluarga.','fa-people-roof','Dewasa',350000.00,'90-120 menit',1,5,'2025-12-25 08:46:27'),
(6,'Peningkatan Percaya Diri','peningkatan-percaya-diri','Membangun kepercayaan diri, mengatasi rasa minder, dan mengembangkan self-esteem yang sehat dengan sugesti positif.','fa-star','Semua',350000.00,'90-120 menit',0,6,'2025-12-25 08:46:27'),
(7,'Mengatasi Kebiasaan Buruk','mengatasi-kebiasaan-buruk','Terapi untuk berhenti dari kebiasaan buruk seperti merokok, overthinking, doom scrolling, dan perilaku negatif lainnya.','fa-ban','Dewasa',350000.00,'90-120 menit',0,7,'2025-12-25 08:46:27'),
(8,'Konseling Online','konseling-online','Sesi konseling dan hipnoterapi via video call untuk Anda yang tidak bisa datang langsung. Fleksibel dan tetap efektif.','fa-video','Semua',350000.00,'90-120 menit',1,8,'2025-12-25 08:46:27');
